import { useParams, useNavigate } from "react-router-dom";
import { useState } from "react";
import "./SalaryHistory.css";

function AddSalary() {
  const { id } = useParams();           // employee id from URL
  const navigate = useNavigate();

  const [salary, setSalary] = useState("");
  const [allowance, setAllowance] = useState("");
  const [deduction, setDeduction] = useState("");
  const [date, setDate] = useState("");

  const handleSubmit = (e) => {
    e.preventDefault();

    const total = Number(salary) + Number(allowance) - Number(deduction);

    const newEntry = {
      empId: id,
      salary,
      allowance,
      deduction,
      total,
      date,
    };

    const existing = JSON.parse(localStorage.getItem("salaryHistory")) || [];
    existing.push(newEntry);

    localStorage.setItem("salaryHistory", JSON.stringify(existing));

    alert("Salary Added Successfully");

    navigate(`/dashboard/employee-details/salary/${id}`);
  };

  return (
    <div className="salary-container">
      <h2>Add Salary</h2>

      <form onSubmit={handleSubmit} className="salary-form">

        <label>Salary</label>
        <input
          type="number"
          required
          value={salary}
          onChange={(e) => setSalary(e.target.value)}
        />

        <label>Allowance</label>
        <input
          type="number"
          required
          value={allowance}
          onChange={(e) => setAllowance(e.target.value)}
        />

        <label>Deduction</label>
        <input
          type="number"
          required
          value={deduction}
          onChange={(e) => setDeduction(e.target.value)}
        />

        <label>Pay Date</label>
        <input
          type="date"
          required
          value={date}
          onChange={(e) => setDate(e.target.value)}
        />

        <button type="submit" className="add-btn">Save Salary</button>
      </form>
    </div>
  );
}

export default AddSalary;
